import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"16. Consultation","description":"","frontmatter":{"title":"16. Consultation","eba":"Health Allied & Managers Admin 2021-2025","topics":["consultation","ohs"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/consultation-disputes/16-consultation.md","filePath":"ebas/has-managers-admin/common-terms/consultation-disputes/16-consultation.md"}'),s={name:"ebas/has-managers-admin/common-terms/consultation-disputes/16-consultation.md"};function a(i,e,p,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_16-consultation" tabindex="-1">16. Consultation <a class="header-anchor" href="#_16-consultation" aria-label="Permalink to &quot;16. Consultation&quot;">​</a></h1><p>Nothing in this clause limits the Employer’s obligations to consult with HSRs under the OHS Act.</p><p><strong>16.1</strong> Consultation regarding major change</p><p><strong>(a)</strong> Where an Employer proposes a major workplace change that may have a significant effect on an Employee or Employees, the Employer will consult with the affected Employee/s, the HWU, and the Employee’s other chosen representative (where relevant) before any proposed change occurs.</p><p><strong>(b)</strong> Workplace change includes (but is not limited to) technological change.</p><p><strong>(c)</strong> Consultation will include those who are absent (including on workers’ compensation or parental leave).</p><p><strong>(d)</strong> The Employer will take reasonable steps to ensure Employees, HSRs (where relevant) and the HWU can participate effectively in the consultation process.</p><p><strong>16.2</strong> Definitions Under this clause 16:</p><p><strong>(a)</strong> Consultation means a genuine opportunity to influence the decision maker, but not joint decision making. It is not merely an announcement as to what is about to happen.</p><p><strong>(b)</strong> Affected employee means an Employee on whom a major workplace change may have a significant effect.</p><p><strong>(c)</strong> Major change means a change in the Employer’s program, production, organisation, physical workplace, workplace arrangements, structure or technology that is likely to have a significant effect on Employees.</p><p><strong>(d)</strong> Significant effect includes but is not limited to:</p><p><strong>(i)</strong> termination of employment;</p><p><strong>(ii)</strong> changes in the size, composition or operation of the Employer’s workforce (including from outsourcing) or skills required;</p><p><strong>(iii)</strong> alteration of the number of hours worked and/or reduction in remuneration;</p><p><strong>(iv)</strong> changes to an Employee’s classification, position description, duties or reporting lines;</p><p><strong>(v)</strong> the need for retraining or relocation/redeployment/transfer to another site or to other work;</p><p><strong>(vi)</strong> removal of an existing amenity;</p><p><strong>(vii)</strong> the removal or reduction of job opportunities, promotion opportunities or job tenure.</p><p><strong>(e)</strong> Measures to mitigate or avert may include but are not limited to:</p><p><strong>(i)</strong> redeployment;</p><p><strong>(ii)</strong> retraining;</p><p><strong>(iii)</strong> salary maintenance;</p><p><strong>(iv)</strong> job sharing; and / or</p><p><strong>(v)</strong> maintenance of accruals.</p><p><strong>16.3</strong> Consultation Steps and Indicative reasonable timeframes</p><p><strong>(a)</strong> Consultation includes the steps set out below.</p><p><strong>(b)</strong> Timeframes for each step must allow a party to consultation (including a representative) to genuinely participate in an informed way having regard for all the circumstances including the complexity of the change proposed, and the need for Employees and their representative to meet with each other and consider and discuss the Employer’s proposal.</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(c)</strong> The following table makes clear the relevant steps and indicative timeframes for the consultation process.</p><p>Step Action Timeframe</p><ol><li><p>Employer provides change impact statement and other written material required by subclause 16.4</p></li><li><p>Written response from Employees 14 days of step 1 and / or HWU</p></li><li><p>Consultation Meeting/s convened 7-14 days of step 2</p></li><li><p>Further Employer response (where After the conclusion of relevant) step 3</p></li><li><p>Alternative proposal from 14 days of step 4 Employees or HWU</p></li><li><p>Employer to consider alternative 14 days of step 5 proposal/s consistent with the obligation to consult and, if applicable, to arrange further meetings with Employees or HWU prior to advising outcome of consultation</p></li></ol><p><strong>16.4</strong> Change Impact Statement (Step 1) Prior to consultation required by this clause, the Employer will provide affected Employee/s and the HWU with a written Change Impact Statement setting out all relevant information including:</p><p><strong>(a)</strong> the details of proposed change;</p><p><strong>(b)</strong> the reasons for the proposed change;</p><p><strong>(c)</strong> the possible effect on Employees of the proposed change on workload and other occupational health and safety impacts;</p><p><strong>(d)</strong> where occupational health and safety impacts are identified, a risk assessment of the potential effects of the change on the health and safety of Employees, undertaken in consultation with HSRs, and the proposed mitigating actions to be implemented to prevent such effects;</p><p><strong>(e)</strong> the expected benefit of the change;</p><p><strong>(f)</strong> measures the Employer is considering that may mitigate or avert the effects of the proposed change;</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(g)</strong> the right of an affected Employee to have a representative including a HWU representative at any time during the change process; and</p><p><strong>(h)</strong> other written material relevant to the reasons for the proposed change (such as consultant reports), excluding material that is commercial in confidence or cannot be disclosed under the Health Services Act 1988 or other legislation.</p><p><strong>16.5</strong> Employee / HWU response (step 2) Following receipt of the change impact statement, affected Employees and / or the HWU may respond in writing to any matter arising from the proposed change.</p><p><strong>16.6</strong> Meetings (step 3)</p><p><strong>(a)</strong> As part of consultation, the Employer will meet with the Employee/s, the HWU and other nominated representative/s (if any) to discuss:</p><p><strong>(i)</strong> the proposed change;</p><p><strong>(ii)</strong> proposals to mitigate or avert the impact of the proposed change;</p><p><strong>(iii)</strong> any matter identified in the written response from the affected Employees and / or the HWU.</p><p><strong>(b)</strong> To avoid doubt, the ‘first meeting’ at step 3 does not limit the number of meetings for consultation.</p><p><strong>16.7</strong> Employer response (step 4) The Employer will give prompt and genuine consideration to matters arising from consultation and will provide a written response to the Employees, the HWU and (where relevant) other representative/s.</p><p><strong>16.8</strong> Alternative proposal (step 5) The affected Employee/s, the HWU and other representative (where relevant) may submit alternative proposal(s) which will take into account the intended objective and benefits of the proposal. Alternative proposals should be submitted in a timely manner so that unreasonable delay may be avoided.</p><p><strong>16.9</strong> Outcome of consultation (step 6) The Employer will give prompt and genuine consideration to matters arising from consultation, including an alternative proposal submitted under sub-clause 16.8, and will advise the affected Employees, the HWU and other nominated representatives (if any) in writing of the outcome of consultation including:</p><p><strong>(a)</strong> whether the Employer intends to proceed with the change proposal;</p><p><strong>(b)</strong> any amendment to the change proposal arising from consultation;</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(c)</strong> details of any measures to mitigate or avert the effect of the changes on affected Employees; and</p><p><strong>(d)</strong> a summary of how matters that have been raised by Employees, the HWU and their representatives, including any alternative proposal, have been taken into account.</p><p><strong>16.10</strong> Consultation about changes to rosters or hours of work</p><p><strong>(a)</strong> Where an Employer proposes to change an Employee’s regular roster or ordinary hours of work, the Employer must consult with the Employee or Employees affected and their representatives, if any, about the proposed change.</p><p><strong>(b)</strong> The Employer must:</p><p><strong>(i)</strong> consider health and safety impacts including fatigue;</p><p><strong>(ii)</strong> provide to the Employee or Employees affected and their representatives, if any, information about the proposed change (for example, information about the nature of the change to the Employee’s regular roster or ordinary hours of work and when that change is proposed to commence);</p><p><strong>(iii)</strong> invite the Employee or Employees affected and their representatives, if any, to give their views about the impact of the proposed change (including any impact in relation to their family or caring responsibilities); and</p><p><strong>(iv)</strong> give consideration to any views about the impact of the proposed change that is given by the Employee or Employees concerned and/or their representatives.</p><p><strong>(c)</strong> The requirement to consult under this clause does not apply where an Employee has irregular, sporadic, unpredictable working hours, self-rostering or, where permitted, a rotating roster.</p><p><strong>(d)</strong> These provisions are to be read in conjunction with the terms of the engagement between the Employer and Employee, other Agreement provisions concerning the scheduling of work and notice requirements.</p><p><strong>16.11</strong> Consultation disputes Any dispute regarding the obligations under this clause will be dealt under the Dispute Resolution Procedure at <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a>.</p><p>Plain language terms: consult, consultation obligations, major workplace change.</p>',68)])])}const d=t(s,[["render",a]]);export{m as __pageData,d as default};
